const incoming = $json.body && typeof $json.body === 'object' ? $json.body : $json;
const order = incoming.data && typeof incoming.data === 'object' ? incoming.data : incoming;
const expectedSharedSecret = 'REPLACE_WITH_SHARED_SECRET';
const hasName = Boolean(order.name && String(order.name).trim());
const hasPhone = Boolean(order.phone && String(order.phone).trim());
const hasAddress = Boolean(order.address && String(order.address).trim());
const hasCart = Array.isArray(order.cart) && order.cart.length > 0;
const sharedSecretValid = Boolean(order.sharedSecret) && order.sharedSecret === expectedSharedSecret;
const isValid = hasName && hasPhone && hasAddress && hasCart && sharedSecretValid;
const validationMessage = !sharedSecretValid ? 'Invalid shared secret' : (!hasName || !hasPhone || !hasAddress || !hasCart ? 'Invalid order payload' : 'ok');
const items = (order.cart || [])
  .map((item) => `- ${item.title} x${item.qty} = ${item.price * item.qty} грн`)
  .join('\n');

return [{
  json: {
    ...order,
    valid: isValid,
    sharedSecretValid,
    validationMessage,
    telegramText: [
      'Нове замовлення з сайту Odesa Coffee Roasters',
      '',
      `Клієнт: ${order.name || '-'}`,
      `Email: ${order.email || '-'}`,
      `Телефон: ${order.phone || '-'}`,
      `Адреса: ${order.address || '-'}`,
      `Сума: ${order.totalLabel || `${order.total || 0} грн`}`,
      '',
      'Товари:',
      items || '-',
      '',
      `Дата: ${order.createdAt || new Date().toISOString()}`,
      `Канал: ${order.deliveryChannel || 'webhook'}`
    ].join('\n'),
    emailText: [
      'Нове замовлення з сайту Odesa Coffee Roasters',
      '',
      `Клієнт: ${order.name || '-'}`,
      `Email: ${order.email || '-'}`,
      `Телефон: ${order.phone || '-'}`,
      `Адреса: ${order.address || '-'}`,
      `Сума: ${order.totalLabel || `${order.total || 0} грн`}`,
      '',
      'Товари:',
      items || '-',
      '',
      `Дата: ${order.createdAt || new Date().toISOString()}`,
      `Джерело: ${order.source || 'website'}`
    ].join('\n')
  }
}];
